class GroundShipping:
    def __init__(self, pounds):
        self.pounds = pounds

    def cost(self):
        return self.pounds * 2

class ExpressShipping:
    def __init__(self, pounds):
        self.pounds = pounds

    def cost(self):
        return self.pounds * 5

def total_shipping(options):
    total = 0
    for option in options:
        total += option.cost()
    return total

